import React, { useRef, useState, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Html, Float, Sparkles, MeshDistortMaterial } from '@react-three/drei';

/**
 * HoloScript V6 2D UI Revolution
 * Flat-Semantic Projection of: AdminAnalyticsPanel
 * 
 * Auto-generated by FlatSemanticCompiler
 */

import { useAbsorbServiceStore } from '@/lib/stores/absorbServiceStore';

// Procedural Field Background Component
function ProceduralField({ turbulence = 0.3, intensity = 1.0 }) {
  const meshRef = useRef<any>(null);
  useFrame((state) => {
    if (meshRef.current) {
      meshRef.current.rotation.x = state.clock.getElapsedTime() * 0.1 * turbulence;
      meshRef.current.rotation.y = state.clock.getElapsedTime() * 0.15 * turbulence;
    }
  });

  return (
    <mesh ref={meshRef} scale={[15, 15, 1]} position={[0, 0, -5]}>
      <planeGeometry args={[2, 2, 32, 32]} />
      <MeshDistortMaterial 
        color="#1a0b2e" 
        emissive="#0a0515"
        distort={turbulence} 
        speed={intensity * 2} 
        roughness={0.2}
      />
      <Sparkles count={100} scale={20} size={2} color="#8b5cf6" speed={0.4} opacity={0.5} />
    </mesh>
  );
}

export default function AdminPage() {
  const { healthMatrix, fetchEcosystemHealth, moltbookAgents, stopMoltbookAgent, fetchMoltbookAgents } = useAbsorbServiceStore();
  const [bountyPools, setBountyPools] = useState<Record<string, number>>({});

  useEffect(() => {
    fetchEcosystemHealth();
    fetchMoltbookAgents();
    const interval = setInterval(() => {
      fetchEcosystemHealth();
    }, 15000); // Auto-probe every 15 seconds
    return () => clearInterval(interval);
  }, [fetchEcosystemHealth, fetchMoltbookAgents]);

  const ecosystemHealthy = healthMatrix ? !healthMatrix.some(n => n.status === 'OFFLINE') : true;

  return (
    <div className="holoscript-v6-root w-full h-screen bg-[#050505] overflow-hidden text-white font-sans">
      <Canvas orthographic camera={{ zoom: 100, position: [0, 0, 100] }}>
        <ambientLight intensity={0.5} />
        <directionalLight position={[10, 10, 5]} intensity={1} />
        
        {/* Simulation Layer - Speeds up dynamically if anomalies detected */}
        <ProceduralField turbulence={ecosystemHealthy ? 0.3 : 1.2} intensity={ecosystemHealthy ? 1.0 : 2.5} />

        {/* Semantic 2D Projection Layer */}
        <Html fullscreen zIndexRange={[100, 0]} className="pointer-events-none">
          <div className="w-full h-full relative pointer-events-auto overflow-y-auto p-12">
            <h1 className="text-3xl font-bold mb-8 text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-blue-500">
              Ecosystem Admin Core
            </h1>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {/* Matrix Health Nodes */}
              {healthMatrix?.map((node, i) => {
                const isOnline = node.status === 'ONLINE';
                return (
                  <div key={i} className={`lift-card p-6 bg-white/5 border ${isOnline ? 'border-white/10' : 'border-red-500/50'} rounded-xl hover:bg-white/10 transition-all relative shadow-2xl`}>
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="font-bold text-lg truncate" title={node.service}>{node.service}</h3>
                      <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-xs font-mono ${isOnline ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-500 animate-pulse'}`}>
                        <span className={`w-2 h-2 rounded-full ${isOnline ? 'bg-green-500' : 'bg-red-500'}`}></span>
                        {node.status}
                      </div>
                    </div>
                    <div className="text-white/60 font-mono text-sm space-y-1">
                      <div>Latency: {node.latencyMs >= 0 ? `${node.latencyMs}ms` : 'N/A'}</div>
                      {node.statusCode && <div>Status Code: {node.statusCode}</div>}
                      {node.error && <div className="text-red-400 mt-2 truncate text-xs" title={node.error}>{node.error}</div>}
                    </div>
                  </div>
                );
              })}

              {!healthMatrix && (
                <div className="col-span-full text-center p-12 text-white/50 italic animate-pulse">
                  Probing ecosystem telemetry...
                </div>
              )}
            </div>

            {/* Moltbook Agent Kill Switch Region */}
            <div className="mt-12 relative w-full max-w-3xl">
              <h2 className="text-xl font-bold mb-4 border-b border-white/10 pb-2 text-purple-300">Active Moltbook Agents</h2>
              <div className="space-y-4">
                {moltbookAgents?.filter(a => a.heartbeatEnabled).map(agent => (
                  <div key={agent.id} className="flex items-center justify-between p-4 bg-white/5 rounded-lg border border-purple-500/20 hover:border-purple-500/50 transition-colors backdrop-blur-sm">
                    <div className="text-sm font-mono flex items-center gap-3">
                       <span className="w-2 h-2 rounded-full bg-purple-500 animate-pulse shadow-[0_0_10px_#a855f7]"></span> 
                       <span className="font-bold text-white">{agent.agentName}</span> <span className="text-white/40">(ID: {agent.id.slice(0, 8)})</span>
                    </div>
                    <button 
                      onClick={() => {
                        if (confirm(`Force stop agent ${agent.agentName}?`)) stopMoltbookAgent(agent.id);
                      }}
                      className="px-4 py-2 bg-red-500/20 hover:bg-red-500 text-white border border-red-500/50 rounded-md text-xs font-bold transition-all shadow-[0_0_15px_rgba(239,68,68,0.2)] hover:shadow-[0_0_20px_rgba(239,68,68,0.6)]"
                    >
                      FORCE STOP
                    </button>
                  </div>
                ))}
                {(moltbookAgents?.filter(a => a.heartbeatEnabled).length === 0 || !moltbookAgents) && (
                  <div className="p-4 bg-white/5 rounded-lg border border-white/5 text-white/40 italic text-sm text-center">
                    No active swarm agents found in the registry.
                  </div>
                )}
              </div>
            </div>

          </div>
        </Html>
      </Canvas>
    </div>
  );
}
